from codebleu import calc_codebleu
from code_bert_score import BERTScorer
import re
import os
import json
import pickle
from metric_passrate_unitest import load_task_ids_from_jsonl, format_passrates

def remove_codecomments(code_with_comments: str) -> str:
    """
    Removes single-line and multi-line comments from Python code,
    and removes any resulting empty lines.
    
    Args:
        code_with_comments (str): The input code as a string with comments.

    Returns:
        str: The code with comments and empty lines removed.
    """
    # Remove all multi-line comments (''' ''' or """ """)
    code_no_multiline_comments = re.sub(r"('''.*?'''|\"\"\".*?\"\"\")", '', code_with_comments, flags=re.DOTALL)

    # Remove single-line comments (excluding # in strings)
    def remove_inline_comments(line):
        in_single_quote = in_double_quote = False
        for i, char in enumerate(line):
            if char == '"' and not in_single_quote:
                in_double_quote = not in_double_quote
            elif char == "'" and not in_double_quote:
                in_single_quote = not in_single_quote
            elif char == '#' and not in_single_quote and not in_double_quote:
                return line[:i].rstrip()
        return line.rstrip()

    # Process each line and remove empty lines
    lines = code_no_multiline_comments.splitlines()
    cleaned_lines = [remove_inline_comments(line) for line in lines]
    non_empty_lines = [line for line in cleaned_lines if line.strip()]

    return '\n'.join(non_empty_lines)


def calculate_codebleu(generated_code_list, reference_code_list, weights):
    generated_code_list = [remove_codecomments(generated_code) for generated_code in generated_code_list]
    reference_code_list = [remove_codecomments(reference_code) for reference_code in reference_code_list]
    return calc_codebleu(reference_code_list, generated_code_list, lang="python", weights=weights, tokenizer=None)

def read_canonical(task_id, word_dir=None):
    if word_dir is None:
        word_dir = 'work_dir'
    file_path = f'{word_dir}/dataset/annotations/annotation_{task_id}/canonical.py'
    if not os.path.exists(file_path):
        raise Exception(f"File not exist {file_path}")
    with open(file_path) as code_file:
        content = code_file.read()
    return content
        

def get_model_code_bert(model, task_ids, result_dir=None):
    if result_dir is None:
        result_dir = 'expriment_result'
    level_results = []
    scorer = BERTScorer(lang="python")
    for guidance_level in [0,1,2,3,4]:
        model_result_dir = os.path.join(result_dir, f'memory_agent_{model}_feedback_fixed_guidance_{guidance_level}')
        bleu_score = []
        for task_id in task_ids:
            if not os.path.exists(os.path.join(model_result_dir, f'task_{task_id}_result.pkl')):
                continue
            with open(os.path.join(model_result_dir, f'task_{task_id}_result.pkl'), 'rb') as result_file:
                result_data = pickle.load(result_file)
            reference_code = [read_canonical(task_id)]
            final_code = [result_data[-1]['final_code']]
            if len(final_code) == 0:
                print(f'model {model} task {task_id} generate empty code')
            bleu_score.append(scorer.score(cands=final_code, refs=reference_code)[2].item())

        ave_score = sum(bleu_score)/len(bleu_score)
        level_results.append(ave_score)
    return level_results

def get_init_model_code_bert(model, task_ids, result_dir=None):
    if result_dir is None:
        result_dir = 'expriment_result'
    level_results = []
    scorer = BERTScorer(lang="python")
    for guidance_level in [0]:
        model_result_dir = os.path.join(result_dir, f'memory_agent_{model}_feedback_fixed_guidance_{guidance_level}')
        bleu_score = []
        for task_id in task_ids:
            if not os.path.exists(os.path.join(model_result_dir, f'task_{task_id}_result.pkl')):
                continue
            with open(os.path.join(model_result_dir, f'task_{task_id}_result.pkl'), 'rb') as result_file:
                result_data = pickle.load(result_file)
            reference_code = [read_canonical(task_id)]
            final_code = [result_data[0]['final_code']]
            if len(final_code) == 0:
                print(f'model {model} task {task_id} generate empty code')
            bleu_score.append(scorer.score(cands=final_code, refs=reference_code)[2].item())

        ave_score = sum(bleu_score)/len(bleu_score)
        level_results.append(ave_score)
    return level_results

