    # task_ids = load_task_ids_from_jsonl()
    # reference_code = ['import math\nimport torch\nimport torch.nn.functional as F\nfrom torch import nn\n\n# Import for Rotary Positional Embeddings, a common technique in modern Transformers.\n# Its use is mentioned in the paper\'s experimental setup (Section 3.3).\nfrom kernel.rotary import apply_rotary_emb\ntry:\n    # Attempt to import FusedRMSNorm from Apex for optimized performance.\n    # This is an efficiency optimization and doesn\'t change the mathematical function.\n    from apex.normalization import FusedRMSNorm as RMSNorm\nexcept ModuleNotFoundError:\n    # Fallback to a standard RMSNorm implementation if Apex is not available.\n    print("No fused RMSNorm")\n    from rms_norm import RMSNorm # Assuming rms_norm.py contains a PyTorch RMSNorm implementation\n\n\n# --- Helper Function for Grouped-Query Attention (GQA) ---\ndef repeat_kv(x: torch.Tensor, n_rep: int) -> torch.Tensor:\n    """\n    Repeats Key (K) and Value (V) tensors for Grouped-Query Attention (GQA).\n    In GQA, multiple query heads can share the same key/value head, reducing\n    computation and memory for K and V projections compared to Multi-Head Attention (MHA).\n    This function is equivalent to torch.repeat_interleave(x, dim=1, repeats=n_rep)\n    if the input `x` was shaped (bs, n_kv_heads, slen * head_dim) and then reshaped,\n    but here it operates on x with shape (bs, n_kv_heads, slen, head_dim) by expanding\n    and reshaping. The dim 1 here refers to the head dimension after transpose.\n\n    Args:\n        x (torch.Tensor): Input Key or Value tensor after transposing to\n                          (batch_size, num_kv_heads_or_values, sequence_length, head_dimension_component).\n                          For K, num_kv_heads_or_values is 2 * num_kv_heads (for K1, K2).\n                          For V, num_kv_heads_or_values is num_kv_heads.\n        n_rep (int): Number of times to repeat each K/V head group.\n                     This is typically num_query_heads / num_kv_heads.\n\n    Returns:\n        torch.Tensor: Repeated K/V tensor.\n                      Shape for K: (batch_size, 2 * num_heads, sequence_length, head_dimension).\n                      Shape for V: (batch_size, num_heads, sequence_length, 2 * head_dimension).\n\n    Paper Correspondence:\n    - The paper mentions the use of Grouped-Query Attention (GQA) in the __init__\n      comments of the MultiheadDiffAttn class description (though not in the main text of Section 2.1).\n    - This is a standard GQA implementation detail.\n    """\n    bs, n_kv_heads_component, slen, head_dim_component = x.shape # Note: n_kv_heads_component is the number of K/V groups to be repeated.\n    if n_rep == 1:\n        # If n_rep is 1, it means num_query_heads == num_kv_heads (no GQA, or MHA setup).\n        # No repetition needed.\n        return x\n    # Expand and reshape to achieve repetition:\n    # 1. Add a new dimension for repetition: x[:, :, None, :, :]\n    #    Shape becomes (bs, n_kv_heads_component, 1, slen, head_dim_component)\n    # 2. Expand along this new dimension: .expand(bs, n_kv_heads_component, n_rep, slen, head_dim_component)\n    #    This copies the K/V head data `n_rep` times.\n    #    Shape becomes (bs, n_kv_heads_component, n_rep, slen, head_dim_component)\n    # 3. Reshape to combine n_kv_heads_component and n_rep: .reshape(bs, n_kv_heads_component * n_rep, slen, head_dim_component)\n    #    This results in the desired shape where the original K/V groups are now repeated to match query head groups.\n    return (\n        x[:, :, None, :, :]\n        .expand(bs, n_kv_heads_component, n_rep, slen, head_dim_component)\n        .reshape(bs, n_kv_heads_component * n_rep, slen, head_dim_component)\n    )\n\n# --- Helper Function for Lambda Initialization ---\ndef lambda_init_fn(depth: int) -> float:\n    """\n    Calculates the initial value for the static component of lambda ($\\lambda_{init}$)\n    based on the layer depth. This function is used to initialize `self.lambda_init`\n    in the `MultiheadDiffAttn` class.\n\n    Args:\n        depth (int): Current layer index (assumed to be 0-indexed by the caller).\n\n    Returns:\n        float: The initial value for $\\lambda_{init}$.\n\n    Paper Correspondence:\n    - This function directly implements the formula provided in Section 2.1 of the paper,\n      just below Equation (2):\n      $\\lambda_{init} = 0.8 - 0.6 \\times \\exp(-0.3 \\cdot (l-1))$\n    - In this code, `depth` corresponds to `(l-1)` from the paper\'s formula,\n      where `l` is the 1-indexed layer number.\n    """\n    return 0.8 - 0.6 * math.exp(-0.3 * depth)\n\n\n# --- Multi-Head Differential Attention Module ---\nclass MultiheadDiffAttn(nn.Module):\n    def __init__(\n        self,\n        embed_dim: int, # Dimension of input embeddings (d_model in the paper).\n        depth: int,      # Current layer index (0-indexed), used for lambda_init_fn.\n        num_heads: int,  # Number of differential attention heads (h in the paper).\n        num_kv_heads: int =None, # Number of Key/Value heads for GQA. If None, defaults to num_heads (MHA).\n    ):\n        super().__init__()\n        self.embed_dim = embed_dim # d_model\n\n        # `num_heads` (h in the paper) for DIFF Transformer is typically set to half\n        # of a baseline Transformer\'s number of attention heads to maintain similar\n        # parameter counts and computational complexity, as mentioned in Section 2.1 and 3.1.\n        # This `num_heads` refers to the number of differential attention units.\n        self.num_heads = num_heads\n\n        # `num_kv_heads` is for Grouped-Query Attention (GQA).\n        # If not specified (None), it defaults to `num_heads`, implying Multi-Head Attention (MHA)\n        # where each differential head has its own K, V projections (before splitting into K1/K2).\n        self.num_kv_heads = num_kv_heads if num_kv_heads is not None else num_heads\n        # Repetition factor for GQA, calculated as num_query_heads / num_kv_heads.\n        # Here, num_query_heads is effectively self.num_heads (number of differential units).\n        self.n_rep = self.num_heads // self.num_kv_heads\n\n        # `head_dim` (d in the paper) is the dimension for EACH of Q1, Q2, K1, K2 vectors.\n        # Paper (Section 2.1) states:\n        # $Q_1, Q_2, K_1, K_2 \\in \\mathbb{R}^{N \\times d}$\n        # $V \\in \\mathbb{R}^{N \\times 2d}$\n        # And for Multi-Head: $h = d_{model} / (2d)$. Rearranging for d: $d = d_{model} / (2h)$.\n        # In code: self.head_dim = embed_dim / (num_heads * 2).\n        self.head_dim = embed_dim // num_heads // 2\n        # Scaling factor for attention scores, $1/\\sqrt{d}$, as per Equation (1).\n        self.scaling = self.head_dim ** -0.5\n\n        # --- Linear Projections for Q, K, V ---\n        # These correspond to $W^Q, W^K, W^V$ in Equation (1) of the paper.\n        # Bias is set to False, a common practice in modern Transformers (e.g., LLaMA),\n        # and mentioned in Appendix B of the paper for their baseline Transformer.\n\n        # Query projection: $XW^Q$. Projects `embed_dim` to `embed_dim`.\n        # The output of this projection will be reshaped to form Q1 and Q2 components\n        # for each of the `num_heads` differential attention heads.\n        # Total projected query dim = num_heads * 2 * head_dim = embed_dim.\n        self.q_proj = nn.Linear(embed_dim, embed_dim, bias=False)\n\n        # Key projection: $XW^K$. Projects `embed_dim` to `embed_dim // n_rep`.\n        # `embed_dim // n_rep` is equivalent to `num_kv_heads * 2 * head_dim`.\n        # This provides the dimensions for K1 and K2 for each of the `num_kv_heads`.\n        self.k_proj = nn.Linear(embed_dim, embed_dim // self.n_rep, bias=False)\n\n        # Value projection: $XW^V$. Projects `embed_dim` to `embed_dim // n_rep`.\n        # `embed_dim // n_rep` is equivalent to `num_kv_heads * 2 * head_dim`.\n        # The paper states $V \\in \\mathbb{R}^{N \\times 2d}$ per head. So for each of the `num_kv_heads`,\n        # the value vector dimension is `2 * head_dim`.\n        self.v_proj = nn.Linear(embed_dim, embed_dim // self.n_rep, bias=False)\n\n        # Output projection: $W^O$ in Equation (3) of the paper.\n        # Projects the concatenated head outputs back to `embed_dim`.\n        self.out_proj = nn.Linear(embed_dim, embed_dim, bias=False)\n\n        # --- Lambda Parameters for Differential Attention ---\n        # These parameters are used to compute the learnable scalar $\\lambda$\n        # as defined in Equation (2) of the paper:\n        # $\\lambda = \\exp(\\lambda_{q_1} \\cdot \\lambda_{k_1}) - \\exp(\\lambda_{q_2} \\cdot \\lambda_{k_2}) + \\lambda_{init}$\n\n        # Static component $\\lambda_{init}$, calculated based on layer depth. `depth` is current layer index.\n        self.lambda_init = lambda_init_fn(depth)\n\n        # Learnable vectors $\\lambda_{q1}, \\lambda_{k1}, \\lambda_{q2}, \\lambda_{k2} \\in \\mathbb{R}^{d}$\n        # where d is `self.head_dim`.\n        # The initialization method (normal distribution with mean=0, std=0.1) is a\n        # practical choice and not specified in the paper\'s core algorithm description.\n        self.lambda_q1 = nn.Parameter(torch.zeros(self.head_dim, dtype=torch.float32).normal_(mean=0,std=0.1))\n        self.lambda_k1 = nn.Parameter(torch.zeros(self.head_dim, dtype=torch.float32).normal_(mean=0,std=0.1))\n        self.lambda_q2 = nn.Parameter(torch.zeros(self.head_dim, dtype=torch.float32).normal_(mean=0,std=0.1))\n        self.lambda_k2 = nn.Parameter(torch.zeros(self.head_dim, dtype=torch.float32).normal_(mean=0,std=0.1))\n\n        # --- Normalization Layer ---\n        # This corresponds to $LN(head_i)$ in Equation (3) and is visualized as "GroupNorm"\n        # in Figure 2 of the paper, applied independently to each head\'s output.\n        # It\'s applied to the result of $(A_1 - \\lambda A_2)V$ for each head.\n        # The dimension of this per-head output is $2 \\times \\text{head\\_dim}$ (the dimension of V for that head).\n        # `eps=1e-5` is a standard epsilon value for RMSNorm.\n        # `elementwise_affine=True` means RMSNorm has learnable gain and bias parameters.\n        self.subln = RMSNorm(2 * self.head_dim, eps=1e-5, elementwise_affine=True)\n\n    def forward(\n        self,\n        x: torch.Tensor, # Input tensor: (batch_size, sequence_length, embed_dim)\n        rel_pos: tuple,  # Positional embeddings (e.g., from RoPE). Passed as a tuple of (cos, sin)\n        attn_mask: torch.Tensor =None, # Attention mask (e.g., for causal decoding)\n    ):\n        bsz, tgt_len, _ = x.size() # bsz: batch_size, tgt_len: target sequence length\n        # embed_dim is also x.size(-1) but not explicitly captured from size() here.\n        src_len = tgt_len # Assuming self-attention, or cross-attention where src_len == tgt_len\n\n        # 1. Project Queries, Keys, Values\n        # Paper Correspondence: $Q = XW^Q, K = XW^K, V = XW^V$ from Eq (1) (conceptually).\n        # q, k, v here are the full projections before reshaping into heads and Q1/Q2 etc.\n        q = self.q_proj(x) # Shape: (bsz, tgt_len, embed_dim)\n        k = self.k_proj(x) # Shape: (bsz, src_len, embed_dim // n_rep)\n        v = self.v_proj(x) # Shape: (bsz, src_len, embed_dim // n_rep)\n\n        # 2. Reshape Q, K, V for Multi-Head Processing\n        # Q: (bsz, tgt_len, 2 * num_heads, head_dim)\n        #   The `2 * num_heads` dimension effectively contains Q1 and Q2 components for all `num_heads`.\n        q = q.view(bsz, tgt_len, 2 * self.num_heads, self.head_dim)\n        # K: (bsz, src_len, 2 * num_kv_heads, head_dim)\n        #   The `2 * num_kv_heads` dimension contains K1 and K2 components for all `num_kv_heads`.\n        k = k.view(bsz, src_len, 2 * self.num_kv_heads, self.head_dim)\n        # V: (bsz, src_len, num_kv_heads, 2 * head_dim)\n        #   Each of the `num_kv_heads` has a value vector of dimension `2 * head_dim` (as V is $2d$ per head).\n        v = v.view(bsz, src_len, self.num_kv_heads, 2 * self.head_dim)\n\n        # 3. Apply Rotary Positional Embeddings (RoPE)\n        # Paper Correspondence: RoPE is mentioned in experimental setups (e.g., Section 3.3)\n        # but not in the core algorithm description in Section 2.1. Its use here is a\n        # standard architectural choice for modern Transformers to inject positional information.\n        # `interleaved=True` is a specific RoPE implementation detail.\n        q = apply_rotary_emb(q, *rel_pos, interleaved=True)\n        k = apply_rotary_emb(k, *rel_pos, interleaved=True)\n        # Note: RoPE is typically applied after reshaping to (bsz, num_heads_total, seq_len, head_dim_component).\n        # The current application is on q(bsz, tgt_len, 2*num_h, h_dim) and k(bsz, src_len, 2*num_kv_h, h_dim).\n        # The apply_rotary_emb function must be compatible with this shape, likely operating on the last two dims.\n\n        # `offset` is used for creating a causal mask if `attn_mask` is None.\n        # For self-attention, src_len == tgt_len, so offset is 0.\n        offset = src_len - tgt_len\n\n        # 4. Transpose and Repeat K, V for GQA\n        # Transpose Q to (bsz, 2 * num_heads, tgt_len, head_dim)\n        q = q.transpose(1, 2)\n        # Transpose K to (bsz, 2 * num_kv_heads, src_len, head_dim) then repeat for GQA.\n        # Resulting K shape: (bsz, 2 * num_heads, src_len, head_dim)\n        k = repeat_kv(k.transpose(1, 2), self.n_rep)\n        # Transpose V to (bsz, num_kv_heads, src_len, 2 * head_dim) then repeat for GQA.\n        # Resulting V shape: (bsz, num_heads, src_len, 2 * head_dim)\n        v = repeat_kv(v.transpose(1, 2), self.n_rep)\n        # At this point:\n        # q: (bsz, 2 * num_heads, tgt_len, head_dim) -> Q1s and Q2s for all diff_heads\n        # k: (bsz, 2 * num_heads, src_len, head_dim) -> K1s and K2s for all diff_heads (after GQA repeat)\n        # v: (bsz, num_heads, src_len, 2*head_dim) -> Vs for all diff_heads (after GQA repeat)\n\n        # 5. Compute Raw Attention Scores (before softmax)\n        # This computes $Q K^T / \\sqrt{d}$.\n        q = q * self.scaling # Apply $1/\\sqrt{d}$ scaling to queries\n        # attn_weights shape: (bsz, 2 * num_heads, tgt_len, src_len)\n        # This tensor contains the raw scores for both $Q_1K_1^T/\\sqrt{d}$ and $Q_2K_2^T/\\sqrt{d}$\n        # interleaved along the `2 * num_heads` dimension.\n        attn_weights = torch.matmul(q, k.transpose(-1, -2))\n\n        # 6. Apply Attention Mask\n        if attn_mask is None:\n            # Create a causal mask if no mask is provided.\n            # This prevents attention to future positions in a sequence.\n            # `torch.triu` creates an upper triangle matrix. `diagonal=1+offset` ensures causality.\n            # For self-attention (offset=0), diagonal is 1 (strict upper triangle).\n            attn_mask = torch.triu(\n                torch.zeros([tgt_len, src_len], device=attn_weights.device, dtype=torch.float) # Ensure same device\n                .fill_(float("-inf")) # Fill with -infinity for masked positions\n                .type_as(attn_weights), # Ensure same dtype as attn_weights\n                1 + offset,\n            )\n            # This mask will be (tgt_len, src_len) and broadcastable.\n\n        # Handle potential NaNs that might arise from masking or other operations.\n        # This is a robustness measure.\n        attn_weights = torch.nan_to_num(attn_weights)\n        # Additive mask application.\n        attn_weights = attn_weights + attn_mask # Additive mask\n        \n        # 7. Apply Softmax to get attention probabilities\n        # Softmax is applied over the `src_len` dimension (dim=-1).\n        # Using float32 for softmax computation can improve numerical stability, then cast back.\n        attn_weights = F.softmax(attn_weights, dim=-1, dtype=torch.float32).type_as(\n            attn_weights # Cast back to original type (e.g. float16 if using mixed precision)\n        )\n        # attn_weights now contains softmax probabilities for both A1 and A2 components, interleaved.\n        # Shape: (bsz, 2 * num_heads, tgt_len, src_len)\n\n        # 8. Calculate the full lambda value (scalar)\n        # Implements Equation (2) from the paper:\n        # $\\lambda = \\exp(\\lambda_{q_1} \\cdot \\lambda_{k_1}) - \\exp(\\lambda_{q_2} \\cdot \\lambda_{k_2}) + \\lambda_{init}$\n        # The dot product `torch.sum(self.lambda_q1 * self.lambda_k1, dim=-1)` is over `head_dim`.\n        # The result `lambda_full` is a scalar that will be shared by all heads in this layer.\n        lambda_1 = torch.exp(torch.sum(self.lambda_q1 * self.lambda_k1, dim=-1).float()).type_as(q)\n        lambda_2 = torch.exp(torch.sum(self.lambda_q2 * self.lambda_k2, dim=-1).float()).type_as(q)\n        lambda_full = lambda_1 - lambda_2 + self.lambda_init\n\n        # 9. Separate A1_probs and A2_probs and compute differential attention scores\n        # Reshape attn_weights to explicitly separate the two components (A1 and A2) for each head.\n        # (bsz, 2 * num_heads, tgt_len, src_len) -> (bsz, num_heads, 2, tgt_len, src_len)\n        attn_weights = attn_weights.view(bsz, self.num_heads, 2, tgt_len, src_len)\n        # Extract A1 probabilities (index 0 of the new dimension)\n        # Extract A2 probabilities (index 1 of the new dimension)\n        # Compute the differential attention scores: $A_1 - \\lambda A_2$\n        # This is the core of the differential attention mechanism from Equation (1) of the paper.\n        attn_weights = attn_weights[:, :, 0] - lambda_full * attn_weights[:, :, 1]\n        # attn_weights shape now: (bsz, num_heads, tgt_len, src_len)\n\n        # 10. Compute Weighted Sum with Values (V)\n        # This calculates $(A_1 - \\lambda A_2)V$ for each head.\n        # attn_weights shape: (bsz, num_heads, tgt_len, src_len)\n        # v (after GQA repeat): (bsz, num_heads, src_len, 2 * head_dim)\n        # attn shape: (bsz, num_heads, tgt_len, 2 * head_dim)\n        attn = torch.matmul(attn_weights, v)\n\n        # 11. Apply Head-wise Normalization (RMSNorm)\n        # Paper Correspondence: This is $LN(head_i)$ in Equation (3) and referred to as\n        # GroupNorm in Figure 2 (implying normalization per head).\n        # RMSNorm normalizes over the last dimension (which is $2 \\times \\text{head\\_dim}$).\n        attn = self.subln(attn)\n        # attn shape: (bsz, num_heads, tgt_len, 2 * head_dim)\n\n        # 12. Apply fixed scaling factor $(1 - \\lambda_{init})$\n        # Paper Correspondence: This matches Equation (3): $\\overline{head_i} = (1 - \\lambda_{init}) \\cdot LN(head_i)$.\n        # This scaling is applied to align gradient flow with standard Transformers (Appendix G).\n        attn = attn * (1 - self.lambda_init)\n\n        # 13. Concatenate Heads and Reshape for Output Projection\n        # Transpose to bring sequence length before heads: (bsz, tgt_len, num_heads, 2 * head_dim)\n        # Reshape to combine head outputs into a single dimension: (bsz, tgt_len, num_heads * 2 * head_dim)\n        # Since num_heads * 2 * head_dim = embed_dim, final shape is (bsz, tgt_len, embed_dim).\n        # Paper Correspondence: This implements $Concat(\\overline{head_1}, ..., \\overline{head_h})$ from Eq (3).\n        attn = attn.transpose(1, 2).reshape(bsz, tgt_len, self.num_heads * 2 * self.head_dim)\n\n        # 14. Final Output Projection\n        # Paper Correspondence: Multiplies by $W^O$ as in Equation (3).\n        attn = self.out_proj(attn) # Shape: (bsz, tgt_len, embed_dim)\n        return attn\n\n']
    # final_code = ['import math\nimport torch\nimport torch.nn.functional as F\nfrom torch import nn\n\nfrom kernel.rotary import apply_rotary_emb\ntry:\n    from apex.normalization import FusedRMSNorm as RMSNorm  # type: ignore\nexcept ModuleNotFoundError:\n    print("No fused RMSNorm")\n    from rms_norm import RMSNorm\n\n\ndef repeat_kv(x: torch.Tensor, n_rep: int) -> torch.Tensor:\n    """Repeat key/value heads along the head dimension for GQA.\n\n    Equivalent to:\n      torch.repeat_interleave(x, dim=1, repeats=n_rep)\n\n    Args:\n        x: Tensor of shape (bsz, n_kv_heads, seq_len, head_dim)\n        n_rep: repetition factor (num_heads // num_kv_heads)\n\n    Returns:\n        Tensor of shape (bsz, n_kv_heads * n_rep, seq_len, head_dim)\n    """\n    bs, n_kv_heads, slen, head_dim = x.shape\n    if n_rep == 1:\n        return x\n    return (\n        x[:, :, None, :, :]\n        .expand(bs, n_kv_heads, n_rep, slen, head_dim)\n        .reshape(bs, n_kv_heads * n_rep, slen, head_dim)\n    )\n\n\nclass MultiheadAttention(nn.Module):\n    def __init__(\n        self,\n        embed_dim,\n        depth,\n        num_heads,\n        num_kv_heads=None,\n    ):\n        super().__init__()\n        self.embed_dim = embed_dim\n        self.num_heads = num_heads\n        self.num_kv_heads = num_kv_heads if num_kv_heads is not None else num_heads\n        self.n_rep = self.num_heads // self.num_kv_heads\n\n        self.head_dim = embed_dim // num_heads\n        self.scaling = self.head_dim ** -0.5\n\n        self.q_proj = nn.Linear(embed_dim, embed_dim, bias=False)\n        self.k_proj = nn.Linear(embed_dim, embed_dim // self.n_rep, bias=False)\n        self.v_proj = nn.Linear(embed_dim, embed_dim // self.n_rep, bias=False)\n        self.out_proj = nn.Linear(embed_dim, embed_dim, bias=False)\n\n    def forward(\n        self,\n        x,\n        rel_pos,\n        attn_mask=None,\n    ):\n        bsz, tgt_len, embed_dim = x.size()\n        src_len = tgt_len\n\n        q = self.q_proj(x)\n        k = self.k_proj(x)\n        v = self.v_proj(x)\n\n        q = q.view(bsz, tgt_len, self.num_heads, self.head_dim)\n        k = k.view(bsz, src_len, self.num_kv_heads, self.head_dim)\n        v = v.view(bsz, src_len, self.num_kv_heads, self.head_dim)\n\n        q = apply_rotary_emb(q, *rel_pos, interleaved=True)\n        k = apply_rotary_emb(k, *rel_pos, interleaved=True)\n\n        offset = src_len - tgt_len\n        q = q.transpose(1, 2)\n        k = repeat_kv(k.transpose(1, 2), self.n_rep)\n        v = repeat_kv(v.transpose(1, 2), self.n_rep)\n        q *= self.scaling\n        attn_weights = torch.matmul(q, k.transpose(-1, -2))\n        if attn_mask is None:\n            attn_mask = torch.triu(\n                torch.zeros([tgt_len, src_len])\n                .float()\n                .fill_(float("-inf"))\n                .type_as(attn_weights),\n                1 + offset,\n            )\n        attn_weights = torch.nan_to_num(attn_weights)\n        attn_weights += attn_mask\n        attn_weights = F.softmax(attn_weights, dim=-1, dtype=torch.float32).type_as(\n            attn_weights\n        )\n\n        attn = torch.matmul(attn_weights, v)\n        attn = attn.transpose(1, 2).reshape(bsz, tgt_len, self.num_heads * self.head_dim)\n\n        attn = self.out_proj(attn)\n        return attn\n\n\ndef lambda_init_fn(depth: int) -> float:\n    """\n    Compute lambda_init per canonical behavior:\n\n      lambda_init = 0.8 - 0.6 * exp(-0.3 * depth)\n\n    This matches the tests\' reference implementation (depth provided directly).\n    """\n    return 0.8 - 0.6 * math.exp(-0.3 * depth)\n\n\nclass MultiheadDiffAttn(nn.Module):\n    """\n    Multi-head Differential Attention:\n\n      DiffAttn(X) = (softmax(Q1 K1^T / sqrt(d)) - lambda * softmax(Q2 K2^T / sqrt(d))) @ V\n\n    Implementation details:\n    - Supports GQA: num_kv_heads may be < num_heads. Keys/Values are repeated across heads.\n    - Each head channel width is 2*d; we set d = embed_dim // (2 * num_heads).\n    - Q/K/V projections produce per-head width 2*d, then split into halves for differential attention.\n    - Applies rotary embedding to Q and K over the full 2*d, then splits into halves (matches canonical).\n    - Per-head RMSNorm is applied over the 2*d channel, then scaled by (1 - lambda_init).\n    - Lambda is reparameterized as exp(λ_q1·λ_k1) - exp(λ_q2·λ_k2) + lambda_init, shared across heads.\n    """\n\n    def __init__(\n        self,\n        embed_dim: int,\n        depth: int,\n        num_heads: int,\n        num_kv_heads: int | None = None,\n    ):\n        super().__init__()\n        self.embed_dim = embed_dim\n        self.num_heads = num_heads\n        self.num_kv_heads = num_kv_heads if num_kv_heads is not None else num_heads\n        assert self.num_heads % self.num_kv_heads == 0, "num_heads must be divisible by num_kv_heads"\n        self.n_rep = self.num_heads // self.num_kv_heads\n\n        # Per-head base dim d, with per-head channel 2*d to accommodate [Q1;Q2], [K1;K2], V\n        self.head_dim = embed_dim // (2 * num_heads)\n        assert self.head_dim * 2 * self.num_heads == embed_dim, "embed_dim must be divisible by 2*num_heads"\n\n        # Scaling factor 1/sqrt(d)\n        self.scaling = self.head_dim ** -0.5\n\n        # Linear projections: Q in full embed_dim; K/V sized for GQA and width 2*d per head\n        self.q_proj = nn.Linear(embed_dim, embed_dim, bias=False)\n        self.k_proj = nn.Linear(embed_dim, embed_dim // self.n_rep, bias=False)\n        self.v_proj = nn.Linear(embed_dim, embed_dim // self.n_rep, bias=False)\n        self.out_proj = nn.Linear(embed_dim, embed_dim, bias=False)\n\n        # Per-head RMSNorm over the 2*d channel\n        self.subln = RMSNorm(2 * self.head_dim, eps=1e-6)\n\n        # Lambda reparameterization vectors in R^d\n        self.lambda_q1 = nn.Parameter(torch.zeros(self.head_dim))\n        self.lambda_k1 = nn.Parameter(torch.zeros(self.head_dim))\n        self.lambda_q2 = nn.Parameter(torch.zeros(self.head_dim))\n        self.lambda_k2 = nn.Parameter(torch.zeros(self.head_dim))\n\n        # Store lambda_init constant for this layer\n        self.lambda_init = float(lambda_init_fn(depth))\n\n    def _compute_lambda(self, device: torch.device, dtype: torch.dtype) -> torch.Tensor:\n        # lambda = exp(λ_q1 · λ_k1) - exp(λ_q2 · λ_k2) + lambda_init\n        dot1 = torch.dot(self.lambda_q1, self.lambda_k1)\n        dot2 = torch.dot(self.lambda_q2, self.lambda_k2)\n        lam = torch.exp(dot1) - torch.exp(dot2) + self.lambda_init\n        return lam.to(device=device, dtype=dtype)\n\n    def forward(\n        self,\n        x: torch.Tensor,\n        rel_pos: tuple,\n        attn_mask: torch.Tensor | None = None,\n    ) -> torch.Tensor:\n        """\n        Args:\n            x: (batch, tgt_len, embed_dim)\n            rel_pos: tuple for rotary embedding\n            attn_mask: optional mask to add to logits; large negative for masked positions\n\n        Returns:\n            Tensor of shape (batch, tgt_len, embed_dim)\n        """\n        bsz, tgt_len, _ = x.size()\n        src_len = tgt_len\n\n        # Projections\n        q = self.q_proj(x)\n        k = self.k_proj(x)\n        v = self.v_proj(x)\n\n        # Reshape into heads with per-head width 2*d\n        q = q.view(bsz, tgt_len, self.num_heads, 2 * self.head_dim)\n        k = k.view(bsz, src_len, self.num_kv_heads, 2 * self.head_dim)\n        v = v.view(bsz, src_len, self.num_kv_heads, 2 * self.head_dim)\n\n        # Apply rotary embedding over the full 2*d, then split into halves (q1/q2, k1/k2)\n        q = apply_rotary_emb(q, *rel_pos, interleaved=True)\n        k = apply_rotary_emb(k, *rel_pos, interleaved=True)\n        q1, q2 = torch.split(q, self.head_dim, dim=-1)\n        k1, k2 = torch.split(k, self.head_dim, dim=-1)\n\n        # Transpose to (bsz, heads, len, dim)\n        q1 = q1.transpose(1, 2)\n        q2 = q2.transpose(1, 2)\n        k1 = k1.transpose(1, 2)\n        k2 = k2.transpose(1, 2)\n        v = v.transpose(1, 2)\n\n        # Repeat K/V to match heads (GQA)\n        k1 = repeat_kv(k1, self.n_rep)\n        k2 = repeat_kv(k2, self.n_rep)\n        v = repeat_kv(v, self.n_rep)\n\n        # Scale queries by 1/sqrt(d)\n        q1 = q1 * self.scaling\n        q2 = q2 * self.scaling\n\n        # Attention logits\n        attn_w1 = torch.matmul(q1, k1.transpose(-1, -2))\n        attn_w2 = torch.matmul(q2, k2.transpose(-1, -2))\n\n        # Causal or provided mask\n        if attn_mask is None:\n            offset = src_len - tgt_len\n            attn_mask = torch.triu(\n                torch.zeros([tgt_len, src_len]).float().fill_(float("-inf")).type_as(attn_w1),\n                1 + offset,\n            )\n\n        # Numerical safety and masking\n        attn_w1 = torch.nan_to_num(attn_w1) + attn_mask\n        attn_w2 = torch.nan_to_num(attn_w2) + attn_mask\n\n        # Softmax\n        p1 = F.softmax(attn_w1, dim=-1, dtype=torch.float32).type_as(attn_w1)\n        p2 = F.softmax(attn_w2, dim=-1, dtype=torch.float32).type_as(attn_w2)\n\n        # Differential attention weights\n        lam = self._compute_lambda(device=attn_w1.device, dtype=attn_w1.dtype)\n        attn_weights = p1 - lam * p2\n\n        # Aggregate values (2*d per head)\n        attn = torch.matmul(attn_weights, v)  # (bsz, heads, tgt_len, 2*d)\n\n        # Per-head RMSNorm then fixed scaling (1 - lambda_init)\n        attn = attn.permute(0, 2, 1, 3)  # (bsz, tgt_len, heads, 2*d)\n        attn = self.subln(attn)\n        attn = attn * (1.0 - self.lambda_init)\n\n        # Concat heads and project\n        attn = attn.reshape(bsz, tgt_len, self.num_heads * (2 * self.head_dim))\n        out = self.out_proj(attn)\n        return out']
